import{_ as a,o as e,c as d,ai as r}from"./chunks/framework.SowO7O0D.js";const T=JSON.parse('{"title":"第十四课：ETF基金","description":"","frontmatter":{},"headers":[],"relativePath":"guide/14-etf.md","filePath":"guide/14-etf.md","lastUpdated":0}'),l={name:"guide/14-etf.md"};function h(i,t,o,n,s,b){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="第十四课-etf基金" tabindex="-1">第十四课：ETF基金 <a class="header-anchor" href="#第十四课-etf基金" aria-label="Permalink to “第十四课：ETF基金”">​</a></h1><p>ETF是&quot;新手最佳选择&quot;，这一课让你彻底搞懂它。</p><h2 id="一、etf是什么" tabindex="-1">一、ETF是什么？ <a class="header-anchor" href="#一、etf是什么" aria-label="Permalink to “一、ETF是什么？”">​</a></h2><p><strong>全称</strong>：Exchange Traded Fund（交易型开放式指数基金）</p><p><strong>一句话理解</strong>：ETF是一个&quot;水果拼盘&quot;，里面装了很多只股票。</p><p>买一个ETF，就等于同时买了篮子里所有的股票。</p><h2 id="二、生活比喻" tabindex="-1">二、生活比喻 <a class="header-anchor" href="#二、生活比喻" aria-label="Permalink to “二、生活比喻”">​</a></h2><p>你想吃水果但不知道哪种好，就买一个&quot;水果拼盘&quot;——里面有苹果、香蕉、橙子，虽然不是每样都最爱，但保证不会踩雷。</p><h2 id="三、a股主要etf" tabindex="-1">三、A股主要ETF <a class="header-anchor" href="#三、a股主要etf" aria-label="Permalink to “三、A股主要ETF”">​</a></h2><table tabindex="0"><thead><tr><th>ETF名称</th><th>代码</th><th>特点</th></tr></thead><tbody><tr><td>沪深300ETF</td><td>510300</td><td>A股最大300只股票</td></tr><tr><td>创业板ETF</td><td>159915</td><td>创业板代表性股票</td></tr><tr><td>科创50ETF</td><td>588000</td><td>科创板最大50只</td></tr><tr><td>证券ETF</td><td>512880</td><td>所有券商股</td></tr><tr><td>芯片ETF</td><td>159995</td><td>芯片行业龙头</td></tr><tr><td>新能源车ETF</td><td>515030</td><td>新能源整车+电池</td></tr></tbody></table><h2 id="四、etf的优势" tabindex="-1">四、ETF的优势 <a class="header-anchor" href="#四、etf的优势" aria-label="Permalink to “四、ETF的优势”">​</a></h2><h3 id="_1-分散风险" tabindex="-1">1. 分散风险 <a class="header-anchor" href="#_1-分散风险" aria-label="Permalink to “1. 分散风险”">​</a></h3><p>不会因为一只股票踩雷而大幅亏损。</p><blockquote><p>如果你只买一只股票，这家公司突然爆雷可能跌50%。 如果你买的是沪深300ETF，单只股票影响很小。</p></blockquote><h3 id="_2-费率低" tabindex="-1">2. 费率低 <a class="header-anchor" href="#_2-费率低" aria-label="Permalink to “2. 费率低”">​</a></h3><p>比主动基金便宜很多。</p><table tabindex="0"><thead><tr><th>费用</th><th>ETF</th><th>主动基金</th></tr></thead><tbody><tr><td>管理费</td><td>0.5%/年</td><td>1.5%/年</td></tr><tr><td>托管费</td><td>0.1%/年</td><td>0.25%/年</td></tr></tbody></table><h3 id="_3-像股票一样交易" tabindex="-1">3. 像股票一样交易 <a class="header-anchor" href="#_3-像股票一样交易" aria-label="Permalink to “3. 像股票一样交易”">​</a></h3><p>在券商APP里直接买卖，和买股票一模一样。</p><h3 id="_4-不需要研究个股" tabindex="-1">4. 不需要研究个股 <a class="header-anchor" href="#_4-不需要研究个股" aria-label="Permalink to “4. 不需要研究个股”">​</a></h3><p>选股很难，ETF帮你一键打包一篮子好股票。</p><h2 id="五、etf-vs-主动基金" tabindex="-1">五、ETF vs 主动基金 <a class="header-anchor" href="#五、etf-vs-主动基金" aria-label="Permalink to “五、ETF vs 主动基金”">​</a></h2><table tabindex="0"><thead><tr><th>对比</th><th>ETF（被动）</th><th>主动基金</th></tr></thead><tbody><tr><td>费率</td><td>低</td><td>高</td></tr><tr><td>收益</td><td>跟随指数</td><td>依赖基金经理</td></tr><tr><td>透明度</td><td>高（持仓公开）</td><td>低（季度更新）</td></tr><tr><td>长期收益</td><td>更稳定</td><td>不确定</td></tr></tbody></table><blockquote><p>💡 数据统计：<strong>长期来看，大多数主动基金跑不赢指数ETF</strong>。</p></blockquote><h2 id="六、如何买卖etf" tabindex="-1">六、如何买卖ETF？ <a class="header-anchor" href="#六、如何买卖etf" aria-label="Permalink to “六、如何买卖ETF？”">​</a></h2><p>在券商APP里，和买股票一模一样：</p><ol><li>打开APP → 点&quot;交易&quot; → &quot;买入&quot;</li><li>输入ETF代码（如510300）</li><li>输入数量（100股=1手）</li><li>确认下单</li></ol><blockquote><p>💡 ETF最小交易单位也是100股。</p></blockquote><h2 id="七、etf适合人群" tabindex="-1">七、ETF适合人群 <a class="header-anchor" href="#七、etf适合人群" aria-label="Permalink to “七、ETF适合人群”">​</a></h2><ul><li>✅ 不愿意研究个股的小白</li><li>✅ 没时间盯盘的上班族</li><li>✅ 追求市场平均收益的稳健投资者</li><li>✅ 想做资产配置的人</li></ul><h2 id="八、etf的风险" tabindex="-1">八、ETF的风险 <a class="header-anchor" href="#八、etf的风险" aria-label="Permalink to “八、ETF的风险”">​</a></h2><blockquote><p>⚠️ <strong>ETF不是保本理财，也有亏损风险。</strong></p></blockquote><ul><li>指数下跌时，ETF也会跌</li><li>行业ETF波动可能很大</li><li>如果买在高位，可能套很久</li></ul><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你是投资新手，有5万元本金打算进入股市。你会选个股还是ETF？为什么？</p></blockquote><hr><p><strong>下一课预告</strong>：ETF搞懂了，下一课学习<strong>基金定投</strong>——懒人理财神器。</p>',37)])])}const p=a(l,[["render",h]]);export{T as __pageData,p as default};
